using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models;

namespace YourNamespace.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly YourDbContext _context;

        public ReviewsController()
        {
            _context = new YourDbContext();
        }

        public ActionResult ProductReviews(int productId)
        {
            var reviews = _context.Reviews
                .Where(r => r.ProductId == productId)
                .Select(r => new ReviewViewModel
                {
                    UserName = r.UserName,
                    Content = r.Content,
                    CreatedAt = r.CreatedAt
                })
                .ToList();

            return View(reviews);
        }
    }
}

// Razor View: ProductReviews.cshtml
@model IEnumerable<YourNamespace.Models.ReviewViewModel>

@foreach (var review in Model)
{
    <div class="review">
        <h4>@Html.Encode(review.UserName)</h4>
        <p>@Html.Raw(SanitizeHtml(review.Content))</p>
        <small>@review.CreatedAt.ToString("g")</small>
    </div>
}

@helper SanitizeHtml(string content)
{
    var allowedTags = new[] { "b", "i" };
    var sanitizer = new Ganss.XSS.HtmlSanitizer(allowedTags);
    @sanitizer.Sanitize(content)
}

